+            ));
+        }
+    }
+    for target in replacement_targets {
+        if !seen_replacements.contains(target.as_str()) {
+            return Err(format!(
+                "replacement target missing explicit module mapping: {target}"
+            ));
+        }
+    }
+    Ok(())
+}
